import { Component } from '@angular/core';
import { FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { finalize } from 'rxjs';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html'
})
export class RegisterComponent {
  loading = false;
  error = '';

  readonly form = this.formBuilder.group({
    name: ['', [Validators.required]],
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(6)]],
    confirmPassword: ['', [Validators.required]]
  });

  constructor(
    private readonly formBuilder: FormBuilder,
    private readonly authService: AuthService,
    private readonly route: ActivatedRoute,
    private readonly router: Router
  ) {
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    const { name, email, password, confirmPassword } = this.form.getRawValue();
    if (password !== confirmPassword) {
      this.error = 'Passwords do not match.';
      return;
    }

    this.loading = true;
    this.error = '';

    this.authService.register({ name: name!, email: email!, password: password! })
      .pipe(finalize(() => (this.loading = false)))
      .subscribe({
        next: () => this.router.navigateByUrl(this.route.snapshot.queryParamMap.get('returnUrl') || '/dashboard'),
        error: (error: { error?: { message?: string } }) => {
          this.error = error.error?.message ?? 'Registration failed.';
        }
      });
  }
}
<div class="shell-card mx-auto max-w-[520px] p-8 md:p-10">
  <p class="eyebrow">Create Account</p>
  <h2 class="section-title mt-3 text-4xl text-[#17172b]">Start your resume workspace</h2>
  <p class="mt-3 text-sm leading-6 text-[#667085]">Register once to save drafts, unlock downloads, and manage ATS-ready versions in one dashboard.</p>

  <form class="mt-8 space-y-4" [formGroup]="form" (ngSubmit)="submit()">
    <div>
      <label class="mb-2 block text-sm font-semibold text-[#475467]">Full name</label>
      <input class="field" type="text" formControlName="name" placeholder="Your full name">
    </div>

    <div>
      <label class="mb-2 block text-sm font-semibold text-[#475467]">Email address</label>
      <input class="field" type="email" formControlName="email" placeholder="you@example.com">
    </div>

    <div>
      <label class="mb-2 block text-sm font-semibold text-[#475467]">Password</label>
      <input class="field" type="password" formControlName="password" placeholder="Minimum 6 characters">
    </div>

    <div>
      <label class="mb-2 block text-sm font-semibold text-[#475467]">Confirm password</label>
      <input class="field" type="password" formControlName="confirmPassword" placeholder="Re-enter password">
    </div>

    <label class="flex items-start gap-3 rounded-2xl bg-[#f8f9ff] px-4 py-3 text-sm leading-6 text-[#667085]">
      <input type="checkbox" class="mt-1 h-4 w-4 accent-[#5b5cf0]">
      I agree to create one secure account for managing resumes, scores, and plan upgrades.
    </label>

    <p *ngIf="error" class="rounded-2xl bg-[#fff1f1] px-4 py-3 text-sm font-medium text-[#ef4444]">{{ error }}</p>

    <button class="btn-primary w-full" type="submit" [disabled]="loading">
      {{ loading ? 'Creating account...' : 'Sign up' }}
    </button>
  </form>

  <div class="mt-6 grid grid-cols-3 gap-3 text-center text-sm">
    <button type="button" class="btn-secondary px-4 py-3">Google</button>
    <button type="button" class="btn-secondary px-4 py-3">LinkedIn</button>
    <button type="button" class="btn-secondary px-4 py-3">GitHub</button>
  </div>

  <p class="mt-6 text-sm text-[#667085]">
    Already have an account?
    <a class="font-bold text-[#5b5cf0]" routerLink="/auth/login">Login</a>
  </p>
</div>
